    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return max(a[2] * 2, a[2]) > max(b[2] * 2, b[2]);
    });

    long long upgrades_used = 0;
    long long min_strength = LLONG_MAX;

    // First pass: try to use upgraded edges if possible
    for (auto& edge : optional_edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long s = edge[2];
        if (dsu.find(u) != dsu.find(v)) {
