        long long u = edge[0];
        long long v = edge[1];
        long long s = edge[2];
        if (dsu_check.find(u) != dsu_check.find(v)) {
            if (upgrades_used < k) {
                s *= 2;
                upgrades_used++;
            }
            dsu_check.unite(u, v);
            min_strength = min(min_strength, s);
        }
    }

    return min_strength;
