class DSU(n: Int) {
  private val parent = Array.ofDim[Int](n)
  private val rank = Array.ofDim[Int](n)

  for (i <- 0 until n) {
    parent(i) = i
  }

  def find(u: Int): Int = {
    if (parent(u) != u) {
      parent(u) = find(parent(u))
    }
    parent(u)
  }

  def unite(u: Int, v: Int): Boolean = {
    val rootU = find(u)
    val rootV = find(v)
    if (rootU == rootV) return false
    if (rank(rootU) < rank(rootV)) {
      parent(rootU) = rootV
    } else {
      parent(rootV) = rootU
      if (rank(rootU) == rank(rootV)) {
        rank(rootU) += 1
      }
    }
    true
  }
}

