    // Sort optional edges by descending strength (original or upgraded)
    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return max(a[2] * 2, a[2]) > max(b[2] * 2, b[2]);
